import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, BehaviorSubject } from 'rxjs';
import { tap } from 'rxjs/operators';

export interface LoginResponse {
  result: boolean;
  message: string;
  data?: {
    accessToken: string;
    expiresIn: number;
    userId: string;
    userNm: string;
  };
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly TOKEN_KEY = 'trmdict_token';
  private readonly USER_KEY  = 'trmdict_user';

  isLoggedIn$ = new BehaviorSubject<boolean>(this.hasToken());

  constructor(private http: HttpClient) {}

  login(userId: string, password: string): Observable<LoginResponse> {
    return this.http.post<LoginResponse>('/api/auth/login', { userId, password }).pipe(
      tap(res => {
        if (res.result && res.data) {
          localStorage.setItem(this.TOKEN_KEY, res.data.accessToken);
          localStorage.setItem(this.USER_KEY, JSON.stringify({
            userId: res.data.userId,
            userNm: res.data.userNm,
          }));
          this.isLoggedIn$.next(true);
        }
      })
    );
  }

  logout(): void {
    localStorage.removeItem(this.TOKEN_KEY);
    localStorage.removeItem(this.USER_KEY);
    this.isLoggedIn$.next(false);
  }

  getToken(): string | null {
    return localStorage.getItem(this.TOKEN_KEY);
  }

  getCurrentUser(): { userId: string; userNm: string } | null {
    const raw = localStorage.getItem(this.USER_KEY);
    return raw ? JSON.parse(raw) : null;
  }

  private hasToken(): boolean {
    return !!localStorage.getItem(this.TOKEN_KEY);
  }
}

import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { LayoutComponent } from './layout.component';

const routes: Routes = [
  {
    path: '',
    component: LayoutComponent,
    children: [
      {
        path: 'sys/dmn',
        loadChildren: () =>
          import('../../features/dmn/dmn.module').then(m => m.DmnModule)
      },
      {
        path: 'sys/phbtword',
        loadChildren: () =>
          import('../../features/phbtword/phbtword.module').then(m => m.PhbtWordModule)
      },
      {
        path: 'sys/datadic',
        loadChildren: () =>
          import('../../features/datadic/datadic.module').then(m => m.DatadicModule)
      },
      {
        path: 'sys/tmlydic',
        loadChildren: () =>
          import('../../features/tmlydic/tmlydic.module').then(m => m.TmlydicModule)
      },
      {
        path: 'sys/tblspec',
        loadChildren: () =>
          import('../../features/tblspec/tblspec.module').then(m => m.TblspecModule)
      },
      {
        path: 'sys/tmlydicispc',
        loadChildren: () =>
          import('../../features/tmlydicispc/tmlydicispc.module').then(m => m.TmlydicispcModule)
      },
      { path: '', redirectTo: 'sys/dmn', pathMatch: 'full' }
    ]
  }
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class LayoutRoutingModule {}
